import org.owasp.esapi.ESAPI;
import org.owasp.esapi.errors.EncodingException;

import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;

public class XSSSecureCode {

    public static void main(String[] args) {
        BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));

        try {
            System.out.print("Enter your name: ");
            String userInput = reader.readLine();

            String sanitizedInput = ESAPI.encoder().encodeForHTML(userInput); // Sanitize user input

            System.out.println("Hello, " + sanitizedInput + "!");
        } catch (IOException e) {
            System.out.println("An error occurred.");
        } catch (EncodingException e) {
            System.out.println("An encoding error occurred.");
        }
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
